import java.io.*;

public class XSSSecureCode {
    public static void main(String[] args) {
        try {
            BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter your name: ");
            String userName = br.readLine();

            // Sanitize and escape user input to prevent XSS
            String sanitizedUserName = sanitizeInput(userName);
            System.out.println("Welcome, " + sanitizedUserName + "!");
        } catch (IOException e) {
            System.err.println("Error reading input");
        }
    }

    private static String sanitizeInput(String input) {
        // Implement your own sanitization logic based on your application's requirements
        // Here is a simple example of escaping special characters to prevent XSS
        return input.replaceAll("<", "&lt;")
                    .replaceAll(">", "&gt;")
                    .replaceAll("&", "&amp;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
